#include <bits/stdc++.h>
using namespace std;

int n, m, a[1000005];

int find(int x) {
    int l = 1, r = n;
    while (l <= r) {
        int mid = (l + r) / 2;
        if (a[mid] < x) {
            l = mid + 1;
        }
        else if (a[mid] >= x) {
            r = mid - 1;
        }
    }
    if (a[l] == x) return l;
    return -1;
}

int main() {
    scanf("%d %d", &n, &m);
    for (int i = 1; i <= n; i++) {
        scanf("%d", a + i);
    }
    for (int i = 1; i <= m; i++) {
        int t;
        scanf("%d", &t);
        printf("%d ", find(t));
    }
}
